1	"use client";
2	
3	import {
4	  useActiveBuybacks,
5	  useBuybackRequests,
6	} from "@/shared/api/query-hooks/use-buyback-requests";
7	import { useFileUpload } from "@/shared/api/query-hooks/use-file-upload";
8	import { useCreateTicket } from "@/shared/api/query-hooks/use-tickets";
9	import type { MimeType } from "@/shared/constants/mime-types";
10	import { S3_FOLDERS } from "@/shared/constants/mime-types";
11	import { TICKET_CATEGORY_LABELS } from "@/shared/constants/ticket";
12	import { generateItemTitle, getSecondaryDisplayInfo } from "@/shared/lib/items";
13	import { sanitizeFileName } from "@/shared/lib/utils/file-name-utils";
14	import { NotificationMedia, TicketCategory } from "@/shared/types/ticket.types";
15	import { Checkbox } from "@/shared/ui/checkbox";
16	import { toast } from "@/shared/ui/notification";
17	import {
18	  Select,
19	  SelectContent,
20	  SelectItem,
21	  SelectTrigger,
22	  SelectValue,
23	} from "@/shared/ui/select";
24	import { zodResolver } from "@hookform/resolvers/zod";
25	import { useCallback, useEffect, useMemo, useRef, useState } from "react";
26	import { type Resolver, useForm } from "react-hook-form";
27	import { z } from "zod";
28	import type { CreateTicketFormProps } from "../model/types";
29	
30	const MAX_FILES = 5;
31	const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5 MB
32	
33	const createTicketSchema = z.object({
34	  description: z
35	    .string()
36	    .min(1, "Description is required")
37	    .min(5, "Description must be at least 5 characters")
38	    .max(2000, "Description must be less than 2000 characters"),
39	  category: z.nativeEnum(TicketCategory, {
40	    errorMap: () => ({ message: "Please select a category" }),
41	  }),
42	  referenceId: z.string().optional(),
43	  attachedFileIds: z
44	    .array(z.string())
45	    .max(MAX_FILES, `Maximum ${MAX_FILES} files allowed`),
46	  preferredContactMethods: z
47	    .array(z.nativeEnum(NotificationMedia))
48	    .min(1, "Select at least one contact method"),
49	});
50	
51	const guestCreateTicketSchema = createTicketSchema.extend({
52	  fullName: z
53	    .string()
54	    .min(1, "Full name is required")
55	    .min(2, "Name must be at least 2 characters"),
56	  email: z
57	    .string()
58	    .min(1, "Email is required")
59	    .email("Please enter a valid email"),
60	});
61	
62	type GuestCreateTicketFormData = z.infer<typeof guestCreateTicketSchema>;
63	
64	export function CreateTicketForm({
65	  onSuccess,
66	  onCancel,
67	  isGuest = false,
68	}: CreateTicketFormProps) {
69	  const [uploadedFiles, setUploadedFiles] = useState<
70	    Array<{ id: string; name: string }>
71	  >([]);
72	  const [isUploadingFiles, setIsUploadingFiles] = useState(false);
73	  const [isDragOver, setIsDragOver] = useState(false);
74	  const [referenceSearch, setReferenceSearch] = useState("");
75	  const [debouncedSearch, setDebouncedSearch] = useState("");
76	  const [isReferenceSelectOpen, setIsReferenceSelectOpen] = useState(false);
77	  const fileInputRef = useRef<HTMLInputElement>(null);
78	
79	  const createTicketMutation = useCreateTicket();
80	  const fileUploadMutation = useFileUpload();
81	
82	  const schema = isGuest ? guestCreateTicketSchema : createTicketSchema;
83	
84	  const {
85	    register,
86	    handleSubmit,
87	    watch,
88	    setValue,
89	    formState: { errors },
90	  } = useForm<GuestCreateTicketFormData>({
91	    resolver: zodResolver(
92	      schema,
93	    ) as unknown as Resolver<GuestCreateTicketFormData>,
94	    defaultValues: {
95	      attachedFileIds: [],
96	      preferredContactMethods: [NotificationMedia.Email],
97	    },
98	  });
99	
100	  const selectedCategory = watch("category");
101	  const selectedContactMethods = watch("preferredContactMethods");
102	  const selectedReferenceId = watch("referenceId");
103	
104	  useEffect(() => {
105	    const timer = setTimeout(() => {
106	      setDebouncedSearch(referenceSearch);
107	    }, 300);
108	
109	    return () => clearTimeout(timer);
110	  }, [referenceSearch]);
111	
112	  const { data: buybacksData, isLoading: isLoadingBuybacks } =
113	    useActiveBuybacks({ search: debouncedSearch || undefined }, !isGuest);
114	
115	  const { data: buybackRequestsData, isLoading: isLoadingBuybackRequests } =
116	    useBuybackRequests({ search: debouncedSearch || undefined }, !isGuest);
117	
118	  function handleContactMethodToggle(method: NotificationMedia) {
119	    const current = selectedContactMethods || [];
120	
121	    if (current.includes(method)) {
122	      const newMethods = current.filter((m) => m !== method);
123	
124	      if (newMethods.length === 0) {
125	        toast.error("At least one contact method is required");
126	
127	        return;
128	      }
129	
130	      setValue("preferredContactMethods", newMethods, { shouldValidate: true });
131	    } else {
132	      setValue("preferredContactMethods", [...current, method], {
133	        shouldValidate: true,
134	      });
135	    }
136	  }
137	
138	  async function processFiles(files: File[]) {
139	    const remainingSlots = MAX_FILES - uploadedFiles.length;
140	
141	    if (remainingSlots <= 0) {
142	      toast.error(`Maximum ${MAX_FILES} files allowed`);
143	
144	      return;
145	    }
146	
147	    const filesToProcess = files.slice(0, remainingSlots);
148	    const oversized = files.filter((f) => f.size > MAX_FILE_SIZE);
149	
150	    if (oversized.length > 0) {
151	      toast.error(`${oversized.length} file(s) exceed the 5 MB limit`);
152	    }
153	
154	    const validFiles = filesToProcess.filter((f) => f.size <= MAX_FILE_SIZE);
155	
156	    if (validFiles.length === 0) return;
157	
158	    setIsUploadingFiles(true);
159	
160	    const uploadResults: Array<{ id: string; name: string }> = [];
161	
162	    for (const file of validFiles) {
163	      try {
164	        const fileNameInfo = sanitizeFileName(file.name);
165	
166	        const result = await fileUploadMutation.mutateAsync({
167	          file,
168	          mime: file.type as MimeType,
169	          fileName: fileNameInfo.sanitized,
170	          folder: S3_FOLDERS.FILES,
171	        });
172	
173	        uploadResults.push({ id: result.fileId, name: fileNameInfo.original });
174	      } catch {
175	        toast.error(`Failed to upload ${file.name}`);
176	      }
177	    }
178	
179	    const newUploadedFiles = [...uploadedFiles, ...uploadResults];
180	
181	    setUploadedFiles(newUploadedFiles);
182	    setValue(
183	      "attachedFileIds",
184	      newUploadedFiles.map((f) => f.id),
185	      { shouldValidate: true },
186	    );
187	
188	    setIsUploadingFiles(false);
189	  }
190	
191	  function handleRemoveFile(fileId: string) {
192	    const newUploadedFiles = uploadedFiles.filter((f) => f.id !== fileId);
193	
194	    setUploadedFiles(newUploadedFiles);
195	    setValue(
196	      "attachedFileIds",
197	      newUploadedFiles.map((f) => f.id),
198	      { shouldValidate: true },
199	    );
200	  }
201	
202	  const handleDragOver = useCallback((e: React.DragEvent) => {
203	    e.preventDefault();
204	    setIsDragOver(true);
205	  }, []);
206	
207	  const handleDragLeave = useCallback((e: React.DragEvent) => {
208	    e.preventDefault();
209	    setIsDragOver(false);
210	  }, []);
211	
212	  function handleDrop(e: React.DragEvent) {
213	    e.preventDefault();
214	    setIsDragOver(false);
215	
216	    const files = Array.from(e.dataTransfer.files);
217	    const accepted = files.filter((f) =>
218	      ["application/pdf", "image/jpeg", "image/png"].includes(f.type),
219	    );
220	
221	    if (accepted.length < files.length) {
222	      toast.error("Only .PDF, .JPG, .PNG files are supported");
223	    }
224	
225	    if (accepted.length > 0) {
226	      processFiles(accepted);
227	    }
228	  }
229	
230	  // biome-ignore lint/suspicious/noExplicitAny: dynamic schema union
231	  async function onSubmit(data: any) {
232	    const subject = data.description.slice(0, 100).trim() || "Support Request";
233	
234	    createTicketMutation.mutate(
235	      {
236	        subject: isGuest ? undefined : subject,
237	        description: data.description,
238	        category: data.category,
239	        referenceId: data.referenceId,
240	        attachedFileIds: data.attachedFileIds,
241	        preferredContactMethods: data.preferredContactMethods,
242	        fullName: isGuest ? data.fullName : undefined,
243	        email: isGuest ? data.email : undefined,
244	      },
245	      {
246	        onSuccess: (ticket) => {
247	          toast.success("Ticket submitted successfully");
248	          onSuccess?.(ticket.id);
249	        },
250	        onError: () => {
251	          console.log("test", data.fullname);
252	          toast.error("Failed to create ticket");
253	        },
254	      },
255	    );
256	  }
257	
258	  const referenceOptions = useMemo(() => {
259	    if (selectedCategory === TicketCategory.ActiveBuyback) {
260	      return (
261	        buybacksData?.data.map((b) => {
262	          const asset = b.asset;
263	          const itemTitle = generateItemTitle(
264	            asset.category.name,
265	            asset.categoryFields,
266	          );
267	          const secondaryInfo = getSecondaryDisplayInfo(
268	            asset.category.name,
269	            asset.categoryFields,
270	          );
271	
272	          return {
273	            value: b.id,
274	            label: `Buyback #${b.id.slice(0, 8)}`,
275	            details: `${itemTitle} · ${secondaryInfo}`,
276	          };
277	        }) || []
278	      );
279	    }
280	
281	    if (selectedCategory === TicketCategory.BuybackRequest) {
282	      return (
283	        buybackRequestsData?.data.map((br) => {
284	          const asset = br.buyback.asset;
285	          const itemTitle = generateItemTitle(
286	            asset.category.name,
287	            asset.categoryFields,
288	          );
289	          const secondaryInfo = getSecondaryDisplayInfo(
290	            asset.category.name,
291	            asset.categoryFields,
292	          );
293	
294	          return {
295	            value: br.id,
296	            label: `Request #${br.id.slice(0, 8)}`,
297	            details: `${itemTitle} · ${secondaryInfo}`,
298	          };
299	        }) || []
300	      );
301	    }
302	
303	    return [];
304	  }, [selectedCategory, buybacksData, buybackRequestsData]);
305	
306	  const isLoadingReference =
307	    selectedCategory === TicketCategory.ActiveBuyback
308	      ? isLoadingBuybacks
309	      : isLoadingBuybackRequests;
310	
311	  const showReferenceSelect =
312	    !isGuest &&
313	    (selectedCategory === TicketCategory.ActiveBuyback ||
314	      selectedCategory === TicketCategory.BuybackRequest);
315	
316	  const descriptionValue = watch("description") || "";
317	  const isSubmitting = createTicketMutation.isPending || isUploadingFiles;
318	
319	  return (
320	    <form className="flex flex-col gap-6" onSubmit={handleSubmit(onSubmit)}>
321	      {/* Guest fields */}
322	      {isGuest && (
323	        <div className="flex flex-col gap-4 sm:flex-row">
324	          <div className="flex flex-1 flex-col gap-1.5">
325	            <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
326	              Full Name <span className="text-red-500">*</span>
327	            </label>
328	            <input
329	              {...register("fullName")}
330	              className="h-12 rounded-[4px] border border-[#A8A29E] bg-transparent px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E] focus:outline-none focus:ring-1 focus:ring-[#021171]"
331	              placeholder="Your full name"
332	            />
333	            {errors.fullName && (
334	              <p className="font-new-sans text-red-500 text-xs">
335	                {errors.fullName.message}
336	              </p>
337	            )}
338	          </div>
339	          <div className="flex flex-1 flex-col gap-1.5">
340	            <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
341	              Email <span className="text-red-500">*</span>
342	            </label>
343	            <input
344	              {...register("email")}
345	              className="h-12 rounded-[4px] border border-[#A8A29E] bg-transparent px-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E] focus:outline-none focus:ring-1 focus:ring-[#021171]"
346	              placeholder="your@email.com"
347	              type="email"
348	            />
349	            {errors.email && (
350	              <p className="font-new-sans text-red-500 text-xs">
351	                {errors.email.message}
352	              </p>
353	            )}
354	          </div>
355	        </div>
356	      )}
357	
358	      {/* Category */}
359	      <div className="flex flex-col gap-1.5">
360	        <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
361	          Category
362	        </label>
363	        <Select
364	          onValueChange={(value) =>
365	            setValue("category", value as TicketCategory, {
366	              shouldValidate: true,
367	            })
368	          }
369	        >
370	          <SelectTrigger
371	            className={`h-12 rounded-[4px] border font-new-sans text-[#44403C] text-sm ${
372	              errors.category ? "border-red-400" : "border-[#A8A29E]"
373	            }`}
374	          >
