391	
392	      {/* Related order */}
393	      {showReferenceSelect && (
394	        <div className="flex flex-col gap-1.5">
395	          <div className="flex items-center gap-2">
396	            <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
397	              Related order
398	            </label>
399	            <svg
400	              aria-hidden="true"
401	              className="text-[#A8A29E]"
