457	                    {debouncedSearch
458	                      ? "No results found"
459	                      : "No items available"}
460	                  </div>
461	                )}
462	                {!isLoadingReference &&
463	                  referenceOptions.map((option) => (
464	                    <SelectItem
465	                      className="cursor-pointer"
466	                      key={option.value}
467	                      value={option.value}
468	                    >
469	                      <div className="flex flex-col gap-0.5">
470	                        <span className="font-medium font-new-sans text-[#44403C]">
471	                          {option.label}
472	                        </span>
473	                        <span className="font-new-sans text-[#A8A29E] text-xs">
474	                          {option.details}
475	                        </span>
476	                      </div>
477	                    </SelectItem>
478	                  ))}
479	              </div>
480	            </SelectContent>
481	          </Select>
482	          <p className="font-new-sans text-[#A8A29E] text-xs">
483	            Select from your previous buybacks, permanent sales, or purchases.
484	          </p>
485	        </div>
486	      )}
487	
488	      {/* Description */}
489	      <div className="flex flex-col gap-1.5">
490	        <label className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
491	          Ticket Description <span className="text-red-500">*</span>
492	        </label>
493	        <textarea
494	          {...register("description")}
495	          className={`resize-none rounded-[4px] border px-3 py-3 font-new-sans text-[#44403C] text-sm placeholder:text-[#A8A29E] focus:outline-none focus:ring-1 focus:ring-[#021171] ${
496	            errors.description ? "border-red-400" : "border-[#A8A29E]"
497	          }`}
498	          maxLength={2100}
499	          placeholder="Enter your message here"
500	          rows={5}
501	        />
502	        <div className="flex items-center justify-between">
503	          {errors.description ? (
504	            <p className="font-new-sans text-red-500 text-xs">
505	              {errors.description.message}
506	            </p>
507	          ) : (
508	            <span />
509	          )}
510	          <span
511	            className={`font-new-sans text-xs ${
512	              descriptionValue.length > 2000 ? "text-red-500" : "text-[#A8A29E]"
513	            }`}
514	          >
515	            {descriptionValue.length}/2000
516	          </span>
517	        </div>
518	      </div>
519	
520	      {/* Attach Support Files */}
521	      <div className="rounded-xl border border-[#D6D3D1] bg-white p-5">
522	        <h3 className="font-light font-new-serif text-[#44403C] text-xl leading-[120%]">
523	          Attach Support Files
524	        </h3>
