import type {
  RaiseTicketDto,
  TicketFilters,
} from "@/shared/types/ticket.types";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { ApiKeys } from "../query-keys";
import { ticketsService } from "../services/tickets.service";

export function useTickets(params?: TicketFilters, enabled = true) {
  return useQuery({
    queryKey: ApiKeys.tickets(params),
    queryFn: () => ticketsService.getMany(params),
    enabled,
  });
}

export function useTicket(id: string) {
  return useQuery({
    queryKey: ApiKeys.tickets(id),
    queryFn: () => ticketsService.getOne(id),
    enabled: !!id,
  });
}

export function useCreateTicket() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (data: RaiseTicketDto) => ticketsService.create(data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.tickets() });
    },
  });
}

export function useDeleteTicket() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (id: string) => ticketsService.delete(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.tickets() });
    },
  });
}

export function useCancelTicket() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (id: string) => ticketsService.cancel(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ApiKeys.tickets() });
    },
  });
}

