import { API_ROUTES } from "@/shared/config/api-routes";
import type {
  RaiseTicketDto,
  Ticket,
  TicketFilters,
  TicketsResponse,
} from "@/shared/types/ticket.types";
import { mainApi } from "../main-api-instance";

export const ticketsService = {
  async getMany(params?: TicketFilters): Promise<TicketsResponse> {
    const response = await mainApi.get<TicketsResponse>(
      API_ROUTES.TICKETS.LIST,
      { params },
    );

    return response.data;
  },

  async getOne(id: string): Promise<Ticket> {
    const response = await mainApi.get<Ticket>(API_ROUTES.TICKETS.GET(id));

    return response.data;
  },

  async create(data: RaiseTicketDto): Promise<Ticket> {
    const response = await mainApi.post<Ticket>(
      API_ROUTES.TICKETS.CREATE,
      data,
    );

    return response.data;
  },

  async cancel(id: string): Promise<void> {
    await mainApi.post(API_ROUTES.TICKETS.CANCEL(id));
  },

  async delete(id: string): Promise<void> {
    await mainApi.delete(API_ROUTES.TICKETS.DELETE(id));
  },
};

