export enum TicketStatus {
  Open = "OPEN",
  Resolved = "RESOLVED",
  Rejected = "REJECTED",
  Cancelled = "CANCELLED",
}

export enum TicketCategory {
  BuybackRequest = "BUYBACK_REQUEST",
  ActiveBuyback = "ACTIVE_BUYBACK",
  Asset = "ASSET",
  Auction = "AUCTION",
  General = "GENERAL",
}

export enum NotificationMedia {
  Email = "EMAIL",
  Phone = "PHONE",
  InApp = "IN_APP",
}

export interface TicketListItem {
  id: string;
  createdAt: string;
  category: TicketCategory;
  subject: string;
  status: TicketStatus;
  referenceId: string | null;
}

export interface Ticket {
  id: string;
  subject: string;
  description: string;
  status: TicketStatus;
  category: TicketCategory;
  referenceId: string | null;
  attachedFiles: string[];
  adminComment: string | null;
  createdAt: string;
  closedAt: string | null;
  preferredContactMethods: NotificationMedia[];
}

export interface TicketListItemAdmin extends TicketListItem {
  userId: string;
}

export interface TicketAdmin extends Ticket {
  user: {
    id: string;
    firstName: string;
    lastName: string;
    patronymic: string | null;
    email: string;
    phoneNumber: string;
  };
  admin: {
    id: string;
    user: {
      firstName: string;
      lastName: string;
      patronymic: string | null;
      email: string;
    };
  } | null;
}

export interface RaiseTicketDto {
  subject?: string;
  description: string;
  category: TicketCategory;
  referenceId?: string;
  attachedFileIds: string[];
  preferredContactMethods: NotificationMedia[];
  fullName?: string;
  email?: string;
}

export interface CloseTicketDto {
  status: TicketStatus.Resolved | TicketStatus.Rejected;
  adminComment: string;
}

export interface TicketFilters {
  search?: string;
  statuses?: TicketStatus[];
  categories?: TicketCategory[];
}

export interface TicketFiltersAdmin extends TicketFilters {
  fromDate?: string;
  toDate?: string;
}

export interface TicketsResponse {
  total: number;
  skip: number;
  take: number;
  data: TicketListItem[];
}

export interface TicketsAdminResponse {
  total: number;
  skip: number;
  take: number;
  data: TicketListItemAdmin[];
}
